import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const ProfilePage = () => {
  const { user, setUser, logout } = useAuth();
  const navigate = useNavigate();
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    fullName: user?.fullName || '',
    bio: user?.bio || ''
  });
  const [uploading, setUploading] = useState(false);
  const [saving, setSaving] = useState(false);

  if (!user) {
    navigate('/');
    return null;
  }

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handlePictureUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setUploading(true);
    try {
      const formData = new FormData();
      formData.append('file', file);

      const response = await axios.post(
        `${process.env.REACT_APP_API_URL || 'http://localhost:5000'}/api/profile/${user._id}/picture`,
        formData,
        { headers: { 'Content-Type': 'multipart/form-data' } }
      );

      setUser(response.data.user);
      alert('Profile picture updated!');
    } catch (error) {
      console.error('Upload error:', error);
      alert('Failed to upload picture');
    } finally {
      setUploading(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const response = await axios.put(
        `${process.env.REACT_APP_API_URL || 'http://localhost:5000'}/api/profile/${user._id}`,
        formData
      );

      setUser(response.data);
      setIsEditing(false);
      alert('Profile updated successfully!');
    } catch (error) {
      console.error('Save error:', error);
      alert('Failed to update profile');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div style={{
      minHeight: 'calc(100vh - 60px)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#f5f5f5',
      padding: '20px'
    }}>
      <div style={{
        background: 'white',
        borderRadius: '20px',
        padding: '40px',
        maxWidth: '500px',
        width: '100%',
        textAlign: 'center',
        boxShadow: '0 10px 40px rgba(0,0,0,0.1)'
      }}>
        <div style={{ position: 'relative', display: 'inline-block', marginBottom: '20px' }}>
          {user.profilePicture ? (
            <img 
              src={user.profilePicture} 
              alt="Profile"
              style={{
                width: '100px',
                height: '100px',
                borderRadius: '50%',
                objectFit: 'cover',
                border: '3px solid #667eea'
              }}
            />
          ) : (
            <div style={{
              width: '100px',
              height: '100px',
              borderRadius: '50%',
              background: user.gender === 'Male'
                ? 'linear-gradient(135deg, #3498db, #2980b9)'
                : 'linear-gradient(135deg, #e91e63, #c2185b)',
              color: 'white',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '40px',
              fontWeight: 'bold'
            }}>
              {user.nickname?.charAt(0).toUpperCase()}
            </div>
          )}
          <label style={{
            position: 'absolute',
            bottom: '0',
            right: '0',
            background: '#667eea',
            color: 'white',
            width: '32px',
            height: '32px',
            borderRadius: '50%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            cursor: 'pointer',
            fontSize: '16px'
          }}>
            {uploading ? '⏳' : '📷'}
            <input
              type="file"
              accept="image/*"
              onChange={handlePictureUpload}
              style={{ display: 'none' }}
              disabled={uploading}
            />
          </label>
        </div>

        <h2 style={{ color: '#333', marginBottom: '10px' }}>{user.nickname}</h2>
        <p style={{
          display: 'inline-block',
          padding: '5px 20px',
          borderRadius: '20px',
          background: user.gender === 'Male' ? '#e3f2fd' : '#fce4ec',
          color: user.gender === 'Male' ? '#1976d2' : '#c2185b',
          marginBottom: '20px'
        }}>
          {user.gender === 'Male' ? '👨' : '👩'} {user.gender}
        </p>

        {isEditing ? (
          <div style={{ textAlign: 'left', marginTop: '20px' }}>
            <label style={{ display: 'block', marginBottom: '5px', color: '#555', fontWeight: '600' }}>
              Full Name
            </label>
            <input
              type="text"
              name="fullName"
              value={formData.fullName}
              onChange={handleInputChange}
              placeholder="Enter your full name"
              style={{
                width: '100%',
                padding: '12px',
                marginBottom: '15px',
                border: '2px solid #e0e0e0',
                borderRadius: '10px',
                fontSize: '14px'
              }}
            />
            <label style={{ display: 'block', marginBottom: '5px', color: '#555', fontWeight: '600' }}>
              Bio
            </label>
            <textarea
              name="bio"
              value={formData.bio}
              onChange={handleInputChange}
              placeholder="Tell us about yourself..."
              rows="4"
              style={{
                width: '100%',
                padding: '12px',
                marginBottom: '15px',
                border: '2px solid #e0e0e0',
                borderRadius: '10px',
                fontSize: '14px',
                resize: 'vertical'
              }}
            />
            <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
              <button
                onClick={handleSave}
                disabled={saving}
                style={{
                  padding: '12px 30px',
                  background: 'linear-gradient(135deg, #667eea, #764ba2)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '25px',
                  fontSize: '16px',
                  cursor: 'pointer',
                  fontWeight: '600'
                }}
              >
                {saving ? 'Saving...' : 'Save'}
              </button>
              <button
                onClick={() => setIsEditing(false)}
                disabled={saving}
                style={{
                  padding: '12px 30px',
                  background: '#e0e0e0',
                  color: '#555',
                  border: 'none',
                  borderRadius: '25px',
                  fontSize: '16px',
                  cursor: 'pointer',
                  fontWeight: '600'
                }}
              >
                Cancel
              </button>
            </div>
          </div>
        ) : (
          <>
            {user.fullName && (
              <p style={{ color: '#555', marginBottom: '10px', fontSize: '16px', fontWeight: '600' }}>
                {user.fullName}
              </p>
            )}
            {user.bio && (
              <p style={{ color: '#777', marginBottom: '15px', fontSize: '14px', lineHeight: '1.6' }}>
                {user.bio}
              </p>
            )}
            <p style={{ color: '#999', fontSize: '14px', marginBottom: '5px' }}>
              {user.isFullAccount ? 'Full Account' : 'Guest User'}
            </p>
            <p style={{ color: '#999', fontSize: '14px', marginBottom: '25px' }}>
              Video calls used: {user.freeCallsUsed || 0}
            </p>
            <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
              <button
                onClick={() => setIsEditing(true)}
                style={{
                  padding: '12px 30px',
                  background: 'linear-gradient(135deg, #667eea, #764ba2)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '25px',
                  fontSize: '16px',
                  cursor: 'pointer',
                  fontWeight: '600'
                }}
              >
                Edit Profile
              </button>
              <button
                onClick={() => { logout(); navigate('/'); }}
                style={{
                  padding: '12px 30px',
                  background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '25px',
                  fontSize: '16px',
                  cursor: 'pointer',
                  fontWeight: '600'
                }}
              >
                Logout
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default ProfilePage;
